import{_ as e,c as r,o as p,ae as t}from"./chunks/framework.BvcDoAct.js";const s=JSON.parse('{"title":"REN (BMSG TRAINEE)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/23_Trainee.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/23_Trainee.md"}'),i={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/23_Trainee.md"};function b(h,a,o,l,n,S){return p(),r("div",null,[...a[0]||(a[0]=[t('<p>Talk about BMSG - Trainee</p><h1 id="ren-bmsg-trainee" tabindex="-1">REN (BMSG TRAINEE) <a class="header-anchor" href="#ren-bmsg-trainee" aria-label="Permalink to &quot;REN (BMSG TRAINEE)&quot;">​</a></h1><h3 id="bmsg-trainee-申请者的内心和对音乐的热爱都会被认真看到-想在sky-hi身边一起做音乐" tabindex="-1">BMSG TRAINEE 申请者的内心和对音乐的热爱都会被认真看到 想在SKY-HI身边一起做音乐 <a class="header-anchor" href="#bmsg-trainee-申请者的内心和对音乐的热爱都会被认真看到-想在sky-hi身边一起做音乐" aria-label="Permalink to &quot;BMSG TRAINEE 申请者的内心和对音乐的热爱都会被认真看到 想在SKY-HI身边一起做音乐&quot;">​</a></h3><p><em>REN：2007年5月11日出生，爱知县出身</em><br><br><br> ————参加选秀的契机是什么？</p><p>看了《THE FIRST》之后，我觉得他们真的有认真去看每个参赛者的内心，还有是不是真的喜欢音乐，这一点特别好。我就想在SKY-HI身边一起做音乐。其实我原本在别的事务所待过一段时间，但一直没有什么起色。我当时想着，如果在初中毕业之前还不能出道，就打算放弃这个梦想。抱着那样的心情去参加了最后一次选秀，结果顺利合格了。</p><p>————在《THE FIRST》里，有什么让你印象特别深刻的画面？</p><p>社长讲到为什么要创立BMSG的时候，我印象特别深。他说，不能只是看着韩国娱乐产业越来越厉害，虽然不是要去对抗，但日本也必须要一起变得更强。 我很喜欢K-POP，但同时也一直想在日本出道。 听到那句话的瞬间，我就觉得——只能是BMSG了。</p><p>————你平时会和SKY-HI聊些什么？</p><p>我如果有烦恼去找他商量，他都会说“我以前也经历过这种事”，然后用自己的经历来回答我，所以特别容易理解。而且现在看他的舞台时，我也会想，“他现在在想什么呢？” 平时他总是有点调皮的样子（笑）。不过在「BMSG FES&#39;24」彩排的时候，我看到他和导演聊天时的表情，是我从来没见过的认真，那一瞬间真的有点被震撼到。</p><p>————你喜欢BMSG的哪些地方？</p><p>很多事情不是只有社长他们自己决定，而是会听我们的想法，然后慢慢变得更好。 如果我说“我想这样做”，他们会马上给我反馈。 就算不能改变，也会认真告诉我理由。 我很喜欢这一点。</p><p>————和前辈艺人有什么故事吗？</p><p>我和GOICHI一起写了一段rap，公司帮我们安排了让Novel Core前辈帮我们指导的机会。 我还和Core前辈交换了LINE。 除了聊音乐，也会问他“你平时在哪里买衣服啊？”这种日常的话题。 能这样聊天，我真的很开心。</p><h2 id="" tabindex="-1"><br><br> <a class="header-anchor" href="#" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="kairi-bmsg-trainee" tabindex="-1">KAIRI（BMSG TRAINEE） <a class="header-anchor" href="#kairi-bmsg-trainee" aria-label="Permalink to &quot;KAIRI（BMSG TRAINEE）&quot;">​</a></h1><h3 id="进入-bmsg-之后-我变得更像自己了。现在可以以真正的自己去做想做的事" tabindex="-1">进入 BMSG 之后，我变得更像自己了。现在可以以真正的自己去做想做的事 <a class="header-anchor" href="#进入-bmsg-之后-我变得更像自己了。现在可以以真正的自己去做想做的事" aria-label="Permalink to &quot;进入 BMSG 之后，我变得更像自己了。现在可以以真正的自己去做想做的事&quot;">​</a></h3><p><em>KAIRI：2010年4月6日出生，大阪府出身</em> <br><br><br></p><p>————选择 BMSG 的契机是什么？</p><p>我原本在大阪的一家舞蹈工作室上课。那里非常重视动作的整齐统一，因此我一直为无法展现自己的个性而烦恼。在按照规定的编舞、规定的角度去跳舞的过程中，我渐渐不知道该如何表达自己的个性。就在那时，我看了《THE FIRST》，看到大家都非常鲜明地展现出各自的个性，我感到十分震撼。我想，自己真正想成为的就是那样的人，于是决定参加选秀。 其实，前辈 edhiii boi 先生原本也在和我同一间工作室，但他在大阪时期和现在的样子完全不同。他的变化也给了我很大的刺激和启发。</p><p>————第一次见到 SKY-HI 先生时的印象是？</p><p>在选秀中第一次见到他的瞬间，我兴奋得有些失控。心脏怦怦直跳，唱歌时甚至紧张到破音。那种“啊，原来真的是这么了不起的人”的心情，很难用语言形容，但直到现在我都还清楚地记得。</p><p>————有没有 SKY-HI 先生对你说过、让你印象深刻的话？</p><p>我是2023年4月成为练习生的。那时候我非常不擅长与人沟通，很难主动开口说话。有一次，我和日高先生单独相处，他对我说：“如果有想说的话，可以说出来的。放轻松一点也没关系。” 听到那句话之后，我整个人都轻松了很多。那句话直到现在仍然留在我心里，也在我与他人沟通时给了我帮助。前阵子合宿结束回程时见到日高先生，他对我说：“你最近变得开朗了呢。”我真的很开心，因为那让我感觉到，他一直在关注我，也理解我。</p><p>————进入 BMSG 之后，你觉得最好的改变是什么？</p><p>我觉得自己的“人”变了。我变得更像自己了。以前做不了想做的事，也存在一个“伪装的自己”。但现在，我可以以真正的自己去做想做的事。我认为这是进入 BMSG 之后最大的改变，也是我最大的幸福。</p><h2 id="-1" tabindex="-1"><br><br> <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="yuta-bmsg-trainee" tabindex="-1">YUTA（BMSG TRAINEE） <a class="header-anchor" href="#yuta-bmsg-trainee" aria-label="Permalink to &quot;YUTA（BMSG TRAINEE）&quot;">​</a></h1><h3 id="在-bmsg-我感受到一种态度-因为舞台会显露出一个人的人性-所以要去锻炼-作为人的力量" tabindex="-1">在 BMSG，我感受到一种态度：因为舞台会显露出一个人的人性，所以要去锻炼“作为人的力量” <a class="header-anchor" href="#在-bmsg-我感受到一种态度-因为舞台会显露出一个人的人性-所以要去锻炼-作为人的力量" aria-label="Permalink to &quot;在 BMSG，我感受到一种态度：因为舞台会显露出一个人的人性，所以要去锻炼“作为人的力量”&quot;">​</a></h3><p><em>YUTA：2007年9月11日出生，东京都出身</em> <br><br><br></p><p>————选择 BMSG 的决定性理由是什么？</p><p>原本我是希望作为舞者在世界范围内活动的。但看到 BMSG 的每位艺人都以各自独特的感性与背景作为武器去表达自我，我就觉得，如果是在这里，也许我所拥有的东西、我所感受到的一切，都能够被更多人知道。</p><p>————SKY-HI 先生说过哪些让你印象深刻的话？</p><p>在第二次合宿、也就是确定我能够加入 BMSG 的那次发表课题曲时，他对我说：“YUTA 的笑容很好。” 其实我本来不是那种常笑的人，也从来没有特别从“笑容”这个角度看待过自己。听到他这么说，我当时心里想：“原来他是这样看我的啊。”那句话让我印象非常深刻，从那之后，我变得更常笑了。 还有一次，我因为课题曲发表得不够好而哭了，他对我说：“眼泪也会成为一种戏剧性。”这句话也深深留在我心里。</p><p>————你觉得 SKY-HI 是怎样的人？</p><p>是一个拥有非常多表达方式的人。之前有机会在他身后伴舞时，我感受到社长所表达的歌曲世界观非常强烈，甚至让我沉浸到几乎忘记自己是在舞台上。 在舞台上，他有一种靠近时会让人感到刺痛般强烈的气场；但私下真实的一面，其实比大家想象中更“SKY-HI”（笑）。 我很喜欢社长。</p><p>————进入 BMSG 之后，你觉得最好的改变是什么？</p><p>这里有很多可以挑战自己、也可以不断研究自己的机会。比如在「BMSG FES&#39;24」的「TRAINEE&#39;s STAGE」上，我每一次都一边观察观众的反应，一边思考什么样的表演才是更好的。 另外，正因为大家都认为“人性会体现在舞台上”，所以我能感受到 BMSG 有一种要去锻炼“人间力”的姿态。我自己在加入 BMSG 之后，性格也发生了非常大的改变。我觉得这是一个甚至能把人的性格往好的方向带动、让人生变得更好的事务所。</p><p>————可以分享一下和前辈艺人的交流吗？</p><p>在练习课题曲《So Good》的时候，我在健身房里让レイちゃん（REIKO）非常仔细地教我唱法，结果真的进步了很多！</p><h2 id="-2" tabindex="-1"><br><br> <a class="header-anchor" href="#-2" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="keito-bmsg-trainee" tabindex="-1">KEITO（BMSG TRAINEE） <a class="header-anchor" href="#keito-bmsg-trainee" aria-label="Permalink to &quot;KEITO（BMSG TRAINEE）&quot;">​</a></h1><h3 id="在梦想破灭、情绪低落的时候-是社长的歌曲拯救了我。知道音乐能带给人勇气后-我开始跳舞" tabindex="-1">在梦想破灭、情绪低落的时候，是社长的歌曲拯救了我。知道音乐能带给人勇气后，我开始跳舞 <a class="header-anchor" href="#在梦想破灭、情绪低落的时候-是社长的歌曲拯救了我。知道音乐能带给人勇气后-我开始跳舞" aria-label="Permalink to &quot;在梦想破灭、情绪低落的时候，是社长的歌曲拯救了我。知道音乐能带给人勇气后，我开始跳舞&quot;">​</a></h3><p><em>KEITO：2009年11月14日出生，埼玉县出身</em> <br><br><br></p><p>————决定成为艺人的契机是什么？</p><p>我从3岁开始练体操，一直到初一。小时候的梦想是参加奥运会。 但是后来成绩一直不如预期，那段时间我非常失落。就在那个时候，我被社长的音乐拯救了。 遇到了《そこにいた》和《Snatchaway》，从中得到了勇气。我那时第一次真正感觉到——“原来音乐可以带给人希望和勇气啊。” 于是从初一开始，我开始学跳舞。因为有看《THE FIRST》，所以也挑战了《MISSIONx2》。虽然没有取得好结果，但因为我真的很喜欢 SKY-HI，也觉得 BMSG 的氛围很亲切，所以后来参加了练习生的选秀。 现在，我和大家一起，一点一点地在成长。</p><p>————第一次见到 SKY-HI 先生时的印象是？</p><p>在《MISSIONx2》的时候，他竟然来到考生的休息室，对我们说“加油哦”。那让我非常惊讶。 那时我才学跳舞一年多，其实很多编舞都还不太明白。但最后我做了两个后空翻。 他对我说“很帅”，我真的特别开心。</p><p>————你觉得 SKY-HI 是怎样的人？</p><p>是一个很会利用零碎时间的人。 在「BMSG FES&#39;24」的时候，我看到他中途好像有点疲惫的表情。但在歌曲与歌曲之间，他会闭上眼睛休息。 我觉得他真的很会抓住空隙，在可以休息的时候就好好休息。</p><p>————进入 BMSG 之后，最好的改变是什么？</p><p>在加入 BMSG 之前，我觉得自己一直是向内缩着、把自己紧紧关起来的状态。 但来到这里之后，我开始能看到周围的人了。 我真心觉得，这是一个会改变人性格的地方。</p><p>————请分享一下和前辈艺人的小故事。</p><p>前几天在事务所里，RYUHEI 君和 JUNON 君在拆足球游戏卡包。那种卡片里有球员签名之类的。 我说我喜欢某个球员，结果后来再见面的时候，RYUHEI 君对我说“送你吧”，然后把那张卡给了我。 真的是非常温柔的前辈。</p><h2 id="-3" tabindex="-1"><br><br> <a class="header-anchor" href="#-3" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="kei-bmsg-trainee" tabindex="-1">KEI（BMSG TRAINEE） <a class="header-anchor" href="#kei-bmsg-trainee" aria-label="Permalink to &quot;KEI（BMSG TRAINEE）&quot;">​</a></h1><h3 id="被社长说了-谢谢你加入bmsg-让我觉得过去经历的一切都不是绕远路" tabindex="-1">被社长说了“谢谢你加入BMSG”，让我觉得过去经历的一切都不是绕远路 <a class="header-anchor" href="#被社长说了-谢谢你加入bmsg-让我觉得过去经历的一切都不是绕远路" aria-label="Permalink to &quot;被社长说了“谢谢你加入BMSG”，让我觉得过去经历的一切都不是绕远路&quot;">​</a></h3><p><em>KEI：2006年7月17日出生，大阪府出身</em> <br><br><br></p><p>————选择 BMSG 的契机是什么？</p><p>我从小的梦想就是成为艺人，也曾经所属过经纪公司，但那和我真正想做的事情不太一样。 即便如此，我还是没办法放弃梦想。就在那个时候，我看到了社长谈论 BMSG 的视频。 我第一次知道，原来有一个人会这么珍惜艺人，并且把“创造文化”这件事看得这么重要，甚至愿意为此拼上全部。 那一刻我就想，一定要在这里出道。</p><p>————真正加入之后，感觉如何？</p><p>这里是一个真的会珍惜每一个人的地方。 和社长的距离也很近，而且能真切地感受到，有很多人都在为了我们而努力。</p><p>————请分享一下和 SKY-HI 先生的故事。</p><p>在选秀时第一次见到他的时候，我完全没想到他会在现场，直接喊了句“哇——！”（笑）。 他对我说“你的眼睛很漂亮”。 因为我看过《THE FIRST》和《MISSIONx2》，知道他经常会说出对人的第一印象，所以当听到属于“我版本”的那句话时，我真的特别感动。 正式进入事务所的时候，社长对我说了“谢谢你加入 BMSG”。 那一瞬间，我突然觉得，自己之前经历的一切都不是绕远路。 眼泪都快掉下来了。 他是我的恩人。</p><p>————你觉得 SKY-HI 是怎样的人？</p><p>当然在工作的时候和私下里是有区分的，但只要一想到日高先生，我脑海里第一个浮现的就是他的笑容。</p><p>————BMSG 是一个怎样的地方？</p><p>自从加入 BMSG 之后，我每天都能感觉到，自己可以很自在地做自己。 这是一个最棒的环境，在最棒的老师们的指导下练习，我真的觉得非常幸福。 我本来就很喜欢看舞者的视频，但在这里上课见到的人，都是以前只能在屏幕上看到的厉害人物…… 能够站上大舞台这种机会，本来就不是理所当然的事情。 有一次作为社长演唱会的开场嘉宾出演，还邀请了父母来现场，他们说感动到大哭。 能够在社长的带领下活动，我真的非常感谢。</p><h2 id="-4" tabindex="-1"><br><br> <a class="header-anchor" href="#-4" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="raiki-bmsg-trainee" tabindex="-1">RAIKI（BMSG TRAINEE） <a class="header-anchor" href="#raiki-bmsg-trainee" aria-label="Permalink to &quot;RAIKI（BMSG TRAINEE）&quot;">​</a></h1><h3 id="跟社长聊了唱歌的烦恼-他对我说-很好啊-就这样去烦恼吧-让我变得更积极了" tabindex="-1">跟社长聊了唱歌的烦恼，他对我说“很好啊，就这样去烦恼吧”，让我变得更积极了 <a class="header-anchor" href="#跟社长聊了唱歌的烦恼-他对我说-很好啊-就这样去烦恼吧-让我变得更积极了" aria-label="Permalink to &quot;跟社长聊了唱歌的烦恼，他对我说“很好啊，就这样去烦恼吧”，让我变得更积极了&quot;">​</a></h3><p><em>RAIKI：2007年5月13日出生，京都府出身</em></p><p><br><br><br></p><p>————选择 BMSG 的契机是什么？</p><p>我从小就非常喜欢AAA。 日高先生是让我想成为艺人的契机，知道他成立了公司之后，我觉得也许在这里可以做我真正想做的事情。 选秀合宿时第一次见到他，他对我说：“比起视频里看到的，你骨架更结实，很不错呢。” 我当时心里想，连这种地方都会注意到啊！</p><p>————让你印象深刻的 SKY-HI 先生的话是？</p><p>在「BMSG FES&#39;24」的间隙，他从远处喊我：“RAIKI！” 然后对我说：“你的歌进步很多啊。” 其实我并没有跟他说过我在为唱歌烦恼，但他却注意到了，我真的觉得他一直都在认真看着我们。 后来我把自己的烦恼告诉他，他对我说：“很好很好，就这样去烦恼吧。” 那句话让我一下子变得积极起来。</p><p>————和 SKY-HI 先生站在同一个舞台上，感觉如何？</p><p>我觉得 SKY-HI 先生是在做最真实的自己地站在舞台上。 他就在我旁边唱歌，还会和我对视…… 那种经历，真的很不可思议。</p><p>————私下里的 SKY-HI 是怎样的人？</p><p>合宿的时候，我们排队准备出去买东西，他明明没有人在看，却对着我们跳舞。 我发现了之后，他反而跳得更起劲了…… 我觉得他不管在哪里、做什么事情都在享受。 他真的在享受人生。 那样的地方让我很向往。</p><p>————加入 BMSG 后觉得最好的事情是什么？</p><p>最重要的，就是可以直接听到作为榜样的日高先生亲自说的话。 他每个月都会来一次成果发表会，如果来不了，也会发很长的邮件给我们反馈。 而且，对从京都来到东京的我来说，BMSG 就像第二个家。 光是待在这里就很开心。 这就是我觉得“加入真是太好了”的理由。</p><p>————请分享一下和前辈艺人的故事。</p><p>我和 MAZZEL 的 KAIRYU 君、HAYATO 君一起打游戏，被狠狠干趴了（笑）。 昨天还和 KAIRI、KANON 君、Aile The Shota 君一起去蒸桑拿！</p><h2 id="-5" tabindex="-1"><br><br> <a class="header-anchor" href="#-5" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="cota-bmsg-trainee" tabindex="-1">COTA（BMSG TRAINEE） <a class="header-anchor" href="#cota-bmsg-trainee" aria-label="Permalink to &quot;COTA（BMSG TRAINEE）&quot;">​</a></h1><h3 id="看了「the-first」之后想把那份-爱-传递出去的心情-在加入-bmsg-之后变得更强烈了" tabindex="-1">看了「THE FIRST」之后想把那份“爱”传递出去的心情，在加入 BMSG 之后变得更强烈了 <a class="header-anchor" href="#看了「the-first」之后想把那份-爱-传递出去的心情-在加入-bmsg-之后变得更强烈了" aria-label="Permalink to &quot;看了「THE FIRST」之后想把那份“爱”传递出去的心情，在加入 BMSG 之后变得更强烈了&quot;">​</a></h3><p><em>COTA：2009年12月6日出生，新潟县出身</em></p><p><br><br><br></p><p>————加入 BMSG 的契机是什么？</p><p>以前我觉得，只要能实现成为唱跳艺人的梦想，进哪家公司都可以。 但是看了「THE FIRST」之后，看到日高先生对参加者说的话，还有他绝对不会否定任何人的样子，我就想，一定要在 BMSG 出道。</p><p>————在「THE FIRST」里特别印象深刻的场面是？</p><p>在合宿第一次审查结果发表之后，日高先生对留下来的成员说： “为了不让在这里落选的人留下遗憾，我们要打造出最好的团队。” 我真的觉得，他是在为所有参与过的人着想。 从那之后，我也开始觉得，就算没有得到好结果，也要继续努力。</p><p>————和 SKY-HI 先生第一次见面的回忆是？</p><p>在选秀时，他站起来看我的表演，而且看得很开心，那样子就和我在电视里看到的一模一样。 结束之后，他对我说：“不管是唱歌还是跳舞，你都有舞台魅力。” 对完全没有唱歌经验的我来说，那句话真的让我很开心，也让我发现了新的自己。</p><p>————作为艺人的 SKY-HI 是怎样的人？</p><p>平时的日高先生就是平时的样子。 但只要看他的表情，有时候会让我觉得，“这是另外一个人吗？” 作为伴舞和他站在同一个舞台上，当他看到我们跳舞而跟着一起嗨起来的时候，我能真的感受到我们是在一起分享音乐。 那是非常珍贵的时间。</p><p>————加入 BMSG 后觉得最好的事情是什么？</p><p>从看「THE FIRST」的时候开始，我自己就发生了变化。 我开始想把爱传递给更多的人。 而这种心情，在加入 BMSG 之后变得更加强烈了。 在 BMSG 经历的所有事情里，都充满了爱。 有很多东西，是只有在 BMSG 才能得到的。 现在的我，是因为加入了 BMSG 才会成为这样的自己。 如果没有来到这里，我的人生一定会完全不一样。 想到这一点，我就会想，要对给了我这种生活的父母、让我们活动的社长和工作人员们，抱着感谢和尊敬的心。 每天都能收到很多建议，也经历了很多开心的时刻。 我想，正是这些，让我慢慢改变了。</p><h2 id="-6" tabindex="-1"><br><br> <a class="header-anchor" href="#-6" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="taichi-bmsg-trainee" tabindex="-1">TAICHI（BMSG TRAINEE） <a class="header-anchor" href="#taichi-bmsg-trainee" aria-label="Permalink to &quot;TAICHI（BMSG TRAINEE）&quot;">​</a></h1><h3 id="sky-hi-先生不是站在上面的人-而是站在大家同样的位置上带领大家的人。我觉得他是一个很有爱的人" tabindex="-1">SKY-HI 先生不是站在上面的人，而是站在大家同样的位置上带领大家的人。我觉得他是一个很有爱的人 <a class="header-anchor" href="#sky-hi-先生不是站在上面的人-而是站在大家同样的位置上带领大家的人。我觉得他是一个很有爱的人" aria-label="Permalink to &quot;SKY-HI 先生不是站在上面的人，而是站在大家同样的位置上带领大家的人。我觉得他是一个很有爱的人&quot;">​</a></h3><p><em>TAICHI：2007年5月16日出生，东京都出身</em></p><p><br><br><br></p><p>————选择 BMSG 的决定性理由是什么？</p><p>通过选秀，我看到了社长和工作人员之间那种很温暖、很像家人一样的关系。 那让我萌生了“我也想成为他们当中的一员”的想法。 我参加过很多日本和韩国经纪公司的选秀，但 BMSG 的选秀，真的就像我在「THE FIRST」里看到的一样。 在第三次审查时第一次见到 SKY-HI 先生，他注意到我穿的靴子，还主动跟我搭话。 后来连工作人员和 Money 先生也一起加入，大家围着我聊起鞋子来（笑）。 完全不像在参加选秀，那种感觉真的让我很震惊。</p><p>————印象最深的 SKY-HI 先生的话是？</p><p>他好像因为某个契机，看到了我在学校活动上跳舞的视频。 听说他当时并不知道视频里的是我。 但他说：“那是只有 TAICHI 才能展现出来的风格，我一下就认出来了。” 在那之前，我其实一直是带着不确定在努力。 但因为他亲口这样告诉我，我第一次获得了很具体的自信。</p><p>————SKY-HI 先生是怎样的人？</p><p>他不是站在上面指挥大家的人，而是站在和大家同样的位置上带着大家往前走的人。 不管是在舞台上还是平时，内在都完全没有改变。 我觉得他是一个非常有爱的人。 而且，真的一点都不虚伪。</p><p>————加入 BMSG 后改变了什么？</p><p>以前我总是很在意别人的评价和目光，感觉箭头一直是向内的。 但现在，每天都能从社长、前辈艺人，还有练习生伙伴们那里得到很多能量。 我觉得自己变得更外向了。 也开始主动去行动。 每天都能感觉到，自己正在越来越接近“艺人的思维”。</p><p>————有和前辈交流吗？</p><p>我在健身房经常会见到 SOTA、RYUHEI 和 JONON。 他们平时和在舞台上简直像两个人。 私下里会和成员们打打闹闹，但一到舞台上就像变身一样……（笑）</p><h2 id="-7" tabindex="-1"><br><br> <a class="header-anchor" href="#-7" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="ryoma-bmsg-trainee" tabindex="-1">RYOMA（BMSG TRAINEE） <a class="header-anchor" href="#ryoma-bmsg-trainee" aria-label="Permalink to &quot;RYOMA（BMSG TRAINEE）&quot;">​</a></h1><h3 id="不仅看发表-也会看练习的样子。-日高先生的这句话一直在鼓励着我" tabindex="-1">“不仅看发表，也会看练习的样子。”日高先生的这句话一直在鼓励着我 <a class="header-anchor" href="#不仅看发表-也会看练习的样子。-日高先生的这句话一直在鼓励着我" aria-label="Permalink to &quot;“不仅看发表，也会看练习的样子。”日高先生的这句话一直在鼓励着我&quot;">​</a></h3><p><em>RYOMA：2008年8月6日出生，长野县出身</em></p><p><br><br><br></p><p>————选择 BMSG 的契机是什么？</p><p>我原本在剧团里做音乐剧。 看了「THE FIRST」之后，我第一次清楚地觉得——“我想成为这个。想成为艺人。” 来参加选秀的人都有很坚定的信念，而且他们唱的歌、跳的舞，和我以前接触的类型完全不一样。 我觉得真的特别帅。</p><p>————第一次见到 SKY-HI 先生是什么时候？</p><p>是在选秀的时候。 而且是在回程的电梯里，刚好变成我们两个人。 他对我说：“特地从长野赶来，谢谢你。” 但我当时太紧张了，只能一直不停地鞠躬（笑）。</p><p>————和 SKY-HI 先生有什么难忘的回忆？</p><p>第一次审查时我失误了，很不甘心，就哭了。 那时候日高先生抱了我很久。 回程的巴士上，他也一直看着我，陪在我身边。 我记得很清楚。 那时候也好，现在也一样，他总是对我说—— “我不仅看发表，也会看你们练习的样子。” 那句话真的给了我很大的勇气。</p><p>————加入 BMSG 后，你觉得自己有什么变化吗？</p><p>我越来越有“自己真的在音乐世界里”的实感。 社长会亲自一对一教我唱歌。 而且这里有这么大的录音室，随时都能拿起麦克风唱歌。 这样的环境让我觉得特别开心。 和加入之前相比，我想音乐的时间大概多了一倍以上。 舞蹈课也会请来各种不同风格的老师，我真的能感觉到自己在成长。 连性格都变了（笑）。 以前我很安静，但不知道什么时候开始，我居然会讲冷笑话了。 我觉得是因为在这里不会被否定，所以心变得更放松了。</p><p>————有和前辈艺人交流吗？</p><p>我经常会见到 RYUHEI。 有一次我们一起看《Blissful》的 MV。 那时候我突然觉得很不可思议—— “画面里的人居然就在我面前……” 明明刚刚还一起去公园玩，一起吃披萨呢……</p><h2 id="-8" tabindex="-1"><br><br> <a class="header-anchor" href="#-8" aria-label="Permalink to &quot;&lt;br/&gt;&lt;br/&gt;&quot;">​</a></h2><p><br><br></p><h1 id="goichi-bmsg-trainee" tabindex="-1">GOICHI（BMSG TRAINEE） <a class="header-anchor" href="#goichi-bmsg-trainee" aria-label="Permalink to &quot;GOICHI（BMSG TRAINEE）&quot;">​</a></h1><h3 id="一个人做不到的事-和练习生们一起就能挑战。能把这样的日常让社长看到-我觉得真的很厉害" tabindex="-1">一个人做不到的事，和练习生们一起就能挑战。能把这样的日常让社长看到，我觉得真的很厉害 <a class="header-anchor" href="#一个人做不到的事-和练习生们一起就能挑战。能把这样的日常让社长看到-我觉得真的很厉害" aria-label="Permalink to &quot;一个人做不到的事，和练习生们一起就能挑战。能把这样的日常让社长看到，我觉得真的很厉害&quot;">​</a></h3><p><em>GOICHI：2006年12月14日出生，埼玉县出身</em></p><p><br><br><br></p><p>————加入 BMSG 的契机是什么？</p><p>从小学一年级开始，我就想成为艺人，所以去学跳舞。 不过那种感觉，其实就像说“我想当假面骑士”一样，是一个大概不会实现的梦想。 但到了要考虑升学方向的时候，我还是觉得自己真正想走的路就是当艺人。 于是我开始一个接一个地去参加选秀。 因为我是 BE:FIRST 的粉丝，所以第一个就报名了最想进的 BMSG，结果合格了。</p><p>————第一次见到 SKY-HI 先生有什么难忘的回忆？</p><p>第一次见面是在合宿的成果发表。 那天我在穿搭上特别用心。毕竟是选秀啊！ 虽然只规定了上下都要黑色，我还是穿了一套天鹅绒的套装。 SKY-HI 先生还夸了我的穿搭。 第一次给社长看表演时，我一开口唱歌，他就站了起来，还把帽子摘下来跟着气氛一起嗨。 还对我说：“你是从哪冒出来的啊！？” 真的超级夸我。 其实比我唱得好、跳得好的人有很多，我也没什么自信能通过。 但就算那天落选，我也会觉得那是一次让我非常有自信的经历。</p><p>————SKY-HI 先生是个什么样的人？</p><p>是个超级有活力的人。 明明应该非常忙，却完全不会让人感觉到。 当我在唱歌或跳舞上有烦恼去找他咨询时，他总是马上就能给出答案。 而且每次听完都会有种“原来是这样！”的冲击感。</p><p>————加入 BMSG 后觉得最好的地方是什么？</p><p>有些事情一个人很难去尝试，但和这些比家人相处时间还长的练习生们一起，就可以反复挑战。 和大家一起做的时候，更容易发现自己的课题。 而且还能把这样的样子让社长看到。 我觉得这样的日常真的很厉害。</p><p>————有和前辈艺人交流吗？</p><p>Novel Core 教过我说唱。 我也问过 Aile The Shot：“你是怎么创作歌曲的？” 还和 RYUHEI 一起吃过披萨。</p>',153)])])}const d=e(i,[["render",b]]);export{s as __pageData,d as default};
